using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// ──────────────────────────────────────────────────────────
// 1) Strongly-typed metadata: get back JsonTypeInfo<T>
// ──────────────────────────────────────────────────────────
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// GetTypeInfo returns the non-generic base; the runtime object is
// actually a JsonTypeInfo<T>, so the cast is safe.
JsonTypeInfo<Person> typed =
    (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));

Console.WriteLine($"Typed metadata  : {typed.Type.Name}  (kind = {typed.Kind})");

// You can now pass it to the generic Serialize/Deserialize overloads:
string json = JsonSerializer.Serialize(new Person("Alice", 30), typed);
Person? roundTripped = JsonSerializer.Deserialize(json, typed);
Console.WriteLine($"Round-tripped   : {roundTripped}");
Console.WriteLine();

// ──────────────────────────────────────────────────────────
// 2) Probe without throwing: TryGetTypeInfo
//    Use a source-gen context that only knows about Person.
// ──────────────────────────────────────────────────────────
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = LimitedContext.Default
};

if (limited.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? personInfo))
{
    var personTyped = (JsonTypeInfo<Person>)personInfo!;
    Console.WriteLine($"Person found    : {personTyped.Type.Name}");
}
else
{
    Console.WriteLine("Person NOT found");
}

// DateTime is NOT in the source-gen context → returns false, no exception.
if (limited.TryGetTypeInfo(typeof(DateTime), out _))
{
    Console.WriteLine("DateTime found");
}
else
{
    Console.WriteLine("DateTime NOT found — and no exception!");
}

// ── types & source-gen context ──────────────────────────
record Person(string Name, int Age);

[JsonSourceGenerationOptions]
[JsonSerializable(typeof(Person))]
partial class LimitedContext : JsonSerializerContext { }

